"""
MKT Context Commentary — Genesis chapters 20–23
Run: python3 scripts/zc-context-genesis-20-23.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (ch22:v1 already present; merge_comm skips it)

Key decisions in this range:
- Ch20:v7 Abraham as nāḇîʾ (prophet): first use of the word "prophet" in the Bible —
  intercession function named before oracle function
- Ch20:v11-12 half-sibling marriage: legally permitted under ANE law (Hammurabi);
  later prohibited by Levitical law (Lev 18:9)
- Ch21:v9 mĕṣaḥēq (mocking/playing): Piel ambiguity noted — not asserting malice
- Ch21:v31 Beersheba etymology: bĕʾēr šābaʿ = well of seven/oath
- Ch22:v2 Moriah: 2 Chr 3:1 identification with Solomon's Temple Mount noted
- Ch22:v9 ʿāqaḏ (bound): hapax legomenon — only use of this verb in the OT
- Ch22:v14 YHWH Yireh: etymology and link to v8's divine "seeing/providing"
- Ch23:v4 gēr-wĕtôšāḇ: first actual land-purchase in the promised land — legal
  significance noted (purchase vs. gift for title security)
- Ch23:v16 silver weighed at merchant standard: pre-coinage ANE commerce explained
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "20": {
    "1": """<p>Abraham's movement from Mamre (18:1; 19:27) into the Negev — the semi-arid transitional zone between Canaan and the Sinai — and settlement at Gerar places him in the territory identified by v32 as belonging to the Philistines. The "Philistines" of the patriarchal period are almost certainly a different group from the later Sea Peoples who settled the coastal plain in the 12th century BCE (the Sea Peoples are documented from Egyptian records of Ramesses III, ca. 1175 BCE); the text uses the later name for the region, as it does with "Dan" (14:14). Gerar is located in the northern Negev, south of Gaza — a semi-nomadic frontier zone where patriarchal herders and settled city-states coexisted.</p>""",
    "2": """<p>The second wife-sister episode (cf. 12:11-20 with Pharaoh in Egypt; and Isaac's variant in 26:7-11). Abimelech (<em>ʾăḇîmelek</em>, "my father is king") is a throne-title rather than a personal name — the same title appears for Ps 34's superscription, for Isaac's Gerar counterpart (26:1), and for a Philistine king in 1 Sam 21:10-15. The repeated deception pattern in the wife-sister episodes is one of the Bible's most uncomfortable recurring features: Abraham uses the same strategy he deployed in ch12, with the same near-catastrophic result. The narrative does not commend the deception; it depicts it and shows YHWH's intervention preserving Sarah despite Abraham's failure.</p>""",
    "3": """<p>YHWH's communication to Abimelech in a dream — the standard ANE form of divine communication to kings (Mesopotamian royal dream-interpretation was a major element of court administration; the Mari texts contain numerous royal dream-reports of divine instruction). YHWH uses the expected communication channel for a pagan king rather than requiring Abimelech to access a different revelatory medium. "You are as good as dead (<em>hinnĕkā mēt</em>)" — the prophetic death-sentence formula, which can be reversed by covenant-compliance (cf. 2 Kgs 20:1: "you will die and not live" reversed in v5: "I will heal you"). The death-sentence for taking a married woman is the legal penalty.</p>""",
    "4": """<p>"Will you destroy an innocent nation (<em>gôy gam-ṣaddîq</em>, a righteous nation)?" — Abimelech's appeal to divine justice mirrors Abraham's intercession for Sodom (18:23: "Will you sweep away the righteous with the wicked?"). The pagan king makes the same appeal to YHWH's standard of justice that the covenant-patriarch made. The narrative irony is pointed: in ch18, Abraham appealed to YHWH's justice for Sodom; now Abimelech makes the same appeal for Gerar — and is successful, where Sodom was not, because Gerar's king genuinely did not know.</p>""",
    "5": """<p>"I have done this with a clear conscience (<em>lĕtōm lĕḇāḇî</em>) and clean hands (<em>ûbĕniqqayôn kappāy</em>)" — the idiom of moral purity before a divine tribunal. The phrase "clean hands and pure heart" (<em>nĕqî kappayim ûḇar-lēḇāḇ</em>) is the qualification for ascending YHWH's mountain in Ps 24:4; Abimelech uses the same moral vocabulary to establish his legal innocence before the divine judge. His defense is legally valid: he acted on information provided to him by both Abraham and Sarah; his ignorance was genuine and not culpable.</p>""",
    "6": """<p>"I know you did this with a clear conscience, and so I have kept you from sinning against me (<em>wāʾeḥśōk gam-ʾānōkî ʾôtĕkā mēḥăṭôʾ-lî</em>)" — the divine restraint operating before the sin occurs. YHWH intervened providentially in Abimelech's court — closing all the women's wombs (v18) and keeping Abimelech from touching Sarah — before any human request. The covenant-woman was protected by divine action even when her covenant-husband failed to protect her. "That is why I did not let you touch her" establishes that divine providence was already operative in the situation before Abraham's intercession (v17) was requested.</p>""",
    "7": """<p>"He is a prophet (<em>nāḇîʾ</em>), and he will pray for you" — the first use of the word "prophet" in the Bible, applied to Abraham. Significantly, the primary function named is intercessory prayer, not prophetic oracle. The prophet as intercessor — the person who stands before YHWH on behalf of others — is the fundamental prophetic function before the prophetic-oracle role is developed (Moses is also described primarily as an intercessor: Exod 32:11; Num 14:13-19; Deut 9:25-29). The "death if you do not return her" is the covenant-enforcement consequence — YHWH's protection of his covenant-partner's household extends to legal enforcement through prophetic pronouncement.</p>""",
    "8": """<p>Abimelech's officials' fear response — "they were very much afraid (<em>wayyîrĕʾû hāʾănāšîm mĕʾōḏ</em>)" — reflects the ANE court's treatment of divine dream-communication as authoritative. In Mesopotamia and Egypt, royal dreams of divine instruction required immediate response; consulting a dream-interpreter and acting on the interpretation was a normal element of royal administration. The court's fear validates Abimelech's own seriousness about the divine warning; the entire court recognizes the authority of the dream-communication.</p>""",
    "9": """<p>Abimelech's moral rebuke of Abraham — "you have done things to me that should never be done (<em>mǎʿăśîm ʾăšer lōʾ-yēʿāśû ʿimmādî</em>)" — the pagan king functions as a moral corrective to the covenant patriarch. This is one of several instances in Genesis where non-Israelite characters display superior ethical behavior to the covenant-people: Abimelech (20:9-10), Potiphar (39:17-20), and later Hiram of Tyre (1 Kgs 5). The narrative does not require Israel to be morally superior to all nations; it shows YHWH working through covenant-faithfulness that sometimes is modeled better by outsiders.</p>""",
    "10": """<p>Abimelech's second question — "what was your reason (<em>mā-rāʾîtā</em>, what did you see)?" — demands not just acknowledgment of the action but explanation of the reasoning. The king insists on understanding the motive before pronouncing final judgment; the judicial practice of hearing the accused's reasoning before rendering verdict is an ANE legal standard (cf. Deut 19:15-19 for the principle of full hearing before judgment). Abraham's answer (vv11-13) provides both the practical reason and the prior arrangement that produced the deception.</p>""",
    "11": """<p>Abraham's explanation — "there is surely no fear of God (<em>yirʾat ʾĕlōhîm</em>) in this place" — is precisely wrong, as the narrative demonstrates. Abimelech received a divine dream, responded to YHWH's instruction, and returned Sarah with generous gifts; the fear of God in Gerar was more evident than Abraham had assumed. The covenant-patriarch's negative assumption about pagan moral capacity was a misjudgment that nearly caused a catastrophe. "They will kill me because of my wife" — the vulnerability of the landless gēr in a foreign king's territory is a real ANE political reality, but Abraham's solution (deception) was not the only available response.</p>""",
    "12": """<p>"She really is my sister, the daughter of my father though not of my mother" — half-sibling marriage from the same father but different mothers was legally permitted in Mesopotamian law (attested in Hammurabi's code and Nuzi tablets) and apparently in the early patriarchal period. The later Levitical law explicitly prohibits it (Lev 18:9: "do not have sexual relations with your sister, either your father's daughter or your mother's daughter"). The patriarchal narratives operate before the Sinai legislation; the retroactive application of Levitical standards to Abraham's marriage is anachronistic. The half-sibling relationship also technically makes the "she is my sister" claim true — the deception is a half-truth, not an outright fabrication.</p>""",
    "13": """<p>"When God had me wander (<em>hittĕʿû ʾōtî ʾĕlōhîm</em>) from my father's household" — the verb <em>hittĕʿû</em> (Hiphil of <em>tāʿāh</em>, to wander/stray) is used for YHWH causing Abraham to leave Ur. The same root describes Israel's wilderness wandering (<em>tāʿāh</em>, Ps 107:4,40) and the spiritual wandering of the lost sheep. Abraham's pre-arranged deception policy ("everywhere we go, say he is my brother") was established at the beginning of the covenant journey — it was a standing instruction to Sarah for the entire journey, not a spontaneous response to Gerar's specific situation. The policy reveals a consistent pattern of self-protective deception that preceded and ran parallel to Abraham's faith.</p>""",
    "14": """<p>Abimelech's gifts to Abraham — "sheep and cattle and male and female slaves" — echo and exceed the gifts Abraham received from Pharaoh in Egypt (12:16). The return of Sarah with a thousand shekels of silver (v16) as public vindication exceeds anything in the Egypt episode. The ironic result of Abraham's deception is material enrichment — the same enrichment pattern as the Egypt episode. The narrative does not present this as divine reward for the deception but as Abimelech's restitution and the working of the divine-provision principle despite human moral failure.</p>""",
    "15": """<p>"My land is before you (<em>ʾarṣî lĕpānêkā</em>)" — Abimelech's open-land offer to Abraham mirrors the same formula used by Lot when offering Abram first choice of the land (13:9: "Is not the whole land before you?"). The Gerar king's generosity to the covenant-patriarch extends beyond restitution to hospitality and territorial access — he offers Abraham freedom to settle anywhere in his land. Abraham's resulting long residence in the Philistine land (v34) follows from this generous invitation.</p>""",
    "16": """<p>"A thousand shekels of silver (<em>ʾelep kesef</em>) — this is to cover the offense against you before all who are with you (<em>kĕsût ʿênayim</em>)" — literally "a covering of eyes," a legal idiom for publicly demonstrated vindication. The thousand shekels is a large public compensatory payment — its purpose is not just restitution but public declaration of Sarah's honor. "You are completely vindicated (<em>wĕnōkāḥat</em>)" — the Niphal of <em>yākah</em> (to be right/vindicated/cleared). The payment is the legal instrument that publicly restores Sarah's honor before Abimelech's entire court community.</p>""",
    "17": """<p>"Abraham prayed to God (<em>wayyitpallēl ʾaḇrāhām ʾel-hāʾĕlōhîm</em>), and God healed Abimelech" — the prophetic intercession promised in v7 is fulfilled. Abraham functioning as a prophet means he stands between the afflicting God and the afflicted community, interceding for healing. The healings — of Abimelech, his wife, and his female slaves — reverse the divine closure of v18. The healing is the covenant-resolution: when the covenant-partner fulfills his prophetic intercession role, the divine judgment is lifted from the pagan community that repented.</p>""",
    "18": """<p>"The LORD had kept all the women in Abimelech's household from conceiving (<em>ʿāṣôr ʿāṣar YHWH bĕʿaḏ kol-reḥem</em>)" — the divine closure of wombs as divine protection of the covenant-woman. The same vocabulary of divine womb-opening and womb-closing appears throughout Genesis and Samuel: YHWH "opened" Rachel's womb (30:22), "remembered" Hannah (1 Sam 1:19-20), and "kept" wombs closed (here). The divine control of fertility is the standard ANE theology of divine sovereignty over the most fundamental biological process; in Israel's covenant-theology, this sovereignty is expressed as protective action for the covenant-family against those who (even unwittingly) threaten it.</p>"""
  },
  "21": {
    "1": """<p>"The LORD was gracious to Sarah as he had said (<em>kaʾăšer ʾāmar</em>)... what he had promised (<em>kaʾăšer dibbēr</em>)" — the double-confirmation of fulfillment (as he said / as he promised) is the narrative's deliberate emphasis on covenant faithfulness. The two phrases distinguish promise (dibbēr, speech/word) and statement (ʾāmar, saying/pronouncement) — both the formal promise (17:19) and the informal announcement (18:10) are fulfilled. YHWH's word-faithfulness is the verse's theological center: the promise made, the promise kept, without remainder or deviation.</p>""",
    "2": """<p>"At the very time God had promised him (<em>lammôʿēd ʾăšer dibber ʾittô ʾĕlōhîm</em>)" — the <em>môʿēd</em> (appointed time/set time) formula of 17:21 and 18:14 is fulfilled exactly. The covenant-heir arrives at the precisely appointed moment — the timing is as theologically significant as the fact. In the ANE, a promise fulfilled at the stated time demonstrated divine reliability in a way that delayed or approximate fulfillment would not. "In his old age" — the age notation reinforces the miraculous character: the child born to a hundred-year-old father and ninety-year-old mother is incontrovertibly the product of divine intervention, not of biological expectation.</p>""",
    "3": """<p>"Abraham gave the name Isaac (<em>yiṣḥāq</em>) to the son Sarah bore him" — following the divine command of 17:19 ("call him Isaac"). The naming is the third beat in the laughter-trilogy: Abraham laughed incredulously at the promise (17:17); Sarah laughed in disbelief at the re-promise (18:12); now the child of impossible promise is born and named for the laughter his coming provoked. The name "he laughs" encapsulates the entire narrative arc: incredulity transformed through divine faithfulness into joy. The covenant-heir is named for the human response to the covenant-promise — the laugh of unbelief that became the laugh of delight.</p>""",
    "4": """<p>"Abraham circumcised him, as God had commanded him" — the covenant-sign applied to the covenant-heir on the eighth day (17:12). Isaac's circumcision on the eighth day (as opposed to Ishmael's at thirteen, 17:25) establishes from birth the covenant-identity marker that distinguishes the covenant-line. The immediate compliance — "Abraham circumcised him" on the stated day — is the narrative's signal that Abraham's covenant-obedience extends to the covenant-heir from the first week of life: the covenant encompasses the child before the child can choose.</p>""",
    "5": """<p>"Abraham was a hundred years old when his son Isaac was born" — the chronological summary closes the age-tracking that has run through the patriarchal narrative. Abraham was 75 at the call (12:4), 86 at Ishmael's birth (16:16), 99 at the covenant-renewal (17:1), and 100 at Isaac's birth. The 25-year gap between promise and fulfillment is the covenant's patience — YHWH waited through Abram's Egypt episode, through the Lot-separation, through the Hagar-Ishmael episode, and through the Abimelech episode before fulfilling the primary promise. The covenant is not hurried by human impatience or altered by human failure.</p>""",
    "6": """<p>Sarah's laughter of joy — "God has brought me laughter (<em>ṣĕḥōq</em>), and everyone who hears about this will laugh with me" — the third and resolving instance of the laughter-root in the Isaac narrative. Abraham's incredulous laugh (17:17) and Sarah's disbelieving laugh (18:12) are resolved into communal joy: "everyone who hears will laugh with me." The name Isaac embeds all three laughs into the covenant-heir's identity — the one who was conceived amid incredulity is born to communal laughter. The communal joy ("everyone who hears") extends the blessing beyond the immediate family: others participate in the covenant-joy of the impossible birth.</p>""",
    "7": """<p>"Who would have said to Abraham that Sarah would nurse children (<em>heitîqāh ḇānîm Śārāh</em>)?" — the nursing (sustained lactation) is the physical evidence of fulfillment that exceeds the bare pregnancy. In the ANE medical understanding, sustained nursing demonstrated the biological reality of the birth more definitively than pregnancy alone. The rhetorical wonder-question ("who would have said?") is the standard biblical form for expressing the gap between what was expected and what occurred: "who has believed our report?" (Isa 53:1); "who has heard such a thing?" (Isa 66:8). The impossibility made possible becomes the paradigm of divine power over natural limitation.</p>""",
    "8": """<p>The weaning feast marks Isaac's survival of the highest-mortality period of ancient childhood. In the ANE, children were typically weaned between two and three years of age; the weaning feast celebrated the child's survival past the most vulnerable period of infancy. Child mortality in the ancient world was extremely high — estimates suggest 30-50% of children died before age five. Isaac's weaning feast is therefore not merely a social celebration but a survival-milestone: the covenant-heir has survived the most dangerous years of life. Abraham's "great feast (<em>mišteh gādôl</em>)" marks the occasion as a covenant-community celebration.</p>""",
    "9": """<p>"Sarah saw that the son whom Hagar the Egyptian had borne to Abraham was mocking (<em>mĕṣaḥēq</em>)" — the Piel of <em>ṣāḥaq</em> (to laugh/play/mock) again. The same root as Isaac's name; the same root as the "joking" of Lot's sons-in-law (19:14). The exact nature of Ishmael's action is ambiguous: the Piel can mean playing/laughing without hostile intent, or mocking/scorning with hostile intent. The LXX adds "with her son Isaac" (paizonta meta Isaak tou huiou autēs); Paul's citation (Gal 4:29: "the son born in the ordinary way persecuted the son born by the power of the Spirit") interprets it as persecution. The narrative's deliberate ambiguity invites the reader's discernment without forcing a verdict.</p>""",
    "10": """<p>Sarah's demand — "the son of the slave woman (<em>ʾāmāh</em>) will never share in the inheritance with my son Isaac" — invokes ANE inheritance law. The Code of Hammurabi (Laws 170-171) distinguishes between the children of a wife and the children of a slave-concubine: if the husband publicly acknowledged the concubine's children, they received a share of the inheritance; but the wife's children took the primary share. Sarah's demand that Ishmael be excluded from the inheritance is a legal claim, not merely an emotional one — she is asserting Isaac's covenantal right as the primary heir against the competing claim of the concubine's son.</p>""",
    "11": """<p>"The matter distressed Abraham greatly because it concerned his son (<em>ʿal-ʾōdôt bĕnô</em>)" — Ishmael is identified as "his son" in Abraham's emotional response. Abraham has raised Ishmael for over thirteen years (Ishmael was born when Abraham was 86, Isaac when he was 100 — Ishmael is now about 16-17 years old). The affective reality of the expulsion — sending away a teenager he has raised from birth — is the narrative's acknowledgment of the genuine human cost. Abraham is not callous; he is in conflict between covenant-clarity (Isaac is the heir) and parental love (Ishmael is his son).</p>""",
    "12": """<p>"It is through Isaac that your offspring will be reckoned (<em>kî bĕyiṣḥāq yiqqārēʾ lĕkā zāraʿ</em>)" — literally "through Isaac shall seed be called to you." The divine explanation resolves the conflict by restating the covenant-priority: the covenant-line runs through Isaac, not Ishmael. Paul cites this verse (Rom 9:7; Heb 11:18) as the foundational statement of the principle of divine election within the physical lineage — not all of Abraham's physical descendants are the covenant-heirs; the covenant-line is defined by divine calling (<em>yiqqārēʾ</em>, will be called/reckoned) rather than mere biological descent.</p>""",
    "13": """<p>"I will make the son of the slave woman into a nation also, because he is your offspring (<em>kî zarʿăkā hûʾ</em>)" — the divine commitment to Ishmael is grounded in the Abrahamic biological connection: "because he is your offspring." The covenant does not encompass Ishmael, but the blessing does; the distinction is precisely Paul's argument in Gal 4:21-31 (the children of the free woman inherit; the children of the slave woman receive blessing but not the inheritance of the covenant). Ishmael's national destiny (twelve princes, 17:20; 25:12-18) is the overflow of Abrahamic blessing, not the covenant itself.</p>""",
    "14": """<p>"Abraham took some food and a skin of water and gave them to Hagar... and sent her off with the boy" — the minimal provision for the desert journey (some food, a single water-skin) is stark. The Beersheba desert is the Negev wilderness south of Canaan — habitable by desert-nomads but dangerous for those without established water sources. The "early next morning" departure parallels Abraham's early-morning departures at moments of covenant-decisive action (19:27; 22:3). The provision, though minimal, is what Abraham could give while obeying the divine command; the narrative does not present him as indifferent to their survival but as constrained by the divine instruction.</p>""",
    "15": """<p>The dehydration crisis — "when the water in the skin was gone, she put the boy under one of the bushes (<em>taḥat ʾaḥad haśśîḥîm</em>)" — the desert landscape of the Beersheba wilderness. Desert shrubs (siḥ, low desert bushes) provide minimal shade but sufficient shelter for a dying child. The narrative's detail is precise and humanly real: Hagar's response to the water-failure is the care of placing the child under what shelter is available before withdrawing to grieve. The physical details of the desert-survival crisis ground the spiritual crisis in material reality.</p>""",
    "16": """<p>"I cannot watch the boy die (<em>ʾal-ʾerʾeh bĕmôt hayyelep</em>)" — the maternal grief of the mother who cannot prevent and cannot witness. "She sat about a bowshot away" — the distance of grief: close enough to hear, far enough not to see. "She began to sob (<em>wattiśśāʾ ʾet-qōlāh wattēḇk</em>)" — the lifting of her voice in weeping is the same idiom used for Esau's weeping (27:38) and Joseph's weeping (45:2; 46:29). The mother's weeping in the desert, unable to save her child, is one of the OT's most humanly immediate grief-portraits.</p>""",
    "17": """<p>"God heard the boy crying (<em>wayyišmaʿ ʾĕlōhîm ʾet-qôl hannaʿar</em>)" — the divine hearing activates the child's name: Ishmael means "God hears" (<em>yišmāʿ ʾēl</em>, 16:11). At the moment of his near-death, the God who named him "God-hears" hears him. The malʾak ʾĕlōhîm (angel of God) rather than the malʾak YHWH of 16:7 appears — the pattern of divine attention to Hagar and Ishmael in the desert is repeated with slightly different divine-name usage, possibly reflecting different source traditions, but the theological content is consistent: YHWH hears the marginalized child in the desert.</p>""",
    "18": """<p>"For I will make him into a great nation (<em>lĕgôy gādôl</em>)" — the promise given to Hagar in 16:10 (innumerable descendants) and to Abraham regarding Ishmael in 17:20 (twelve rulers, a great nation) is now directly given again in the moment of Ishmael's near-death. The promise is reiterated at the point of its apparent dissolution: precisely when the covenant-obligation seems most at risk (the heir of the promise is dying in the desert), YHWH intervenes to fulfill it. The same pattern — promise at the moment of greatest threat — characterizes the entire patriarchal narrative.</p>""",
    "19": """<p>"Then God opened her eyes and she saw a well of water (<em>bĕʾēr māyim</em>)" — the divine gift of perception of what was already present. The well was presumably there; Hagar's crisis-blindness prevented her from seeing it. Whether the well is a miraculous creation or a miraculous revelation of existing water, the narrative attributes both the seeing and the water to divine provision. The well in the desert as a sign of divine provision becomes one of the OT's signature images of grace in extremity — the same pattern governs Elijah's desert provision (1 Kgs 19:5-8) and the wilderness water miracles (Exod 15:22-25; 17:1-7; Num 20:2-11).</p>""",
    "20": """<p>"God was with the boy (<em>wayhî ʾĕlōhîm ʾet-hannaʿar</em>) as he grew up" — the divine-presence formula applied to Ishmael. The same formula characterizes the covenant-line: YHWH is "with" Isaac (26:3,24), Jacob (28:15; 31:3; 35:3), Joseph (39:2,21,23), and Moses. Ishmael receives covenant-presence language even though he is outside the covenant-line — YHWH's presence is not confined to the covenant-holder. "He lived in the desert and became an archer (<em>rōḇeh qešet</em>)" — the archer as the desert-warrior; the wild-donkey description of 16:12 (free and fierce in the wilderness) is fulfilled in the desert-archer lifestyle. The Desert of Paran becomes Ishmael's territory.</p>""",
    "21": """<p>"His mother got a wife for him from Egypt (<em>miṣrāyim</em>)" — Hagar the Egyptian secures an Egyptian wife for her son; the marriage pattern connects Ishmael to Egypt (Hagar's homeland) and establishes the Arabian peoples who descend from him as having Egyptian maternal lineage through Ishmael's wife. In the ANE, mothers arranged marriages for their sons (Rebekah's role in 27:46-28:5; Hagar's role here); the mother's negotiation of the marriage was the standard practice in a patriarchal household where the father's authority was primary but the mother's relational networks were the practical resource for marriage-arrangement.</p>""",
    "22": """<p>"God is with you in everything you do (<em>ʾĕlōhîm ʿimmĕkā bĕkōl ʾăšer-ʾattāh ʿōśeh</em>)" — Abimelech's observation is a pagan king's theological recognition of the covenant-God's activity through the covenant-partner. The same recognition appears repeatedly in the patriarchal narratives: Pharaoh recognizes the divine spirit in Joseph (41:38-39); Laban recognizes that YHWH has blessed him because of Jacob (30:27). The divine-presence-that-makes-prosperous (<em>ʾĕlōhîm ʿimmĕkā</em>) is the signature of the covenant-bearer that the surrounding nations observe without necessarily sharing.</p>""",
    "23": """<p>Abimelech's covenant-request uses the vocabulary of <em>ḥesed</em> — "show to me the same kindness (<em>ḥesed</em>) I have shown to you" — the covenant-loyalty word that characterizes YHWH's relationship to Israel. The pagan king invokes <em>ḥesed</em> as the basis for a treaty: mutual covenant-loyalty between neighboring parties. The request follows the ANE non-aggression treaty format: a mutual oath of <em>ḥesed</em> (covenant-kindness/loyalty) toward each other's descendants "to the country where you now reside as a foreigner (<em>bāʾāreṣ ʾăšer-gartāh bāh</em>)" — Abraham's gēr status in the land is formally acknowledged even as Abimelech seeks a permanent covenant with him.</p>""",
    "24": """<p>"I swear it (<em>ʾānōkî ʾiššāḇēaʿ</em>)" — Abraham's oath-response to Abimelech's treaty-request is immediate and unqualified. The formal oath (<em>šābaʿ</em>) is the standard ANE treaty-ratification speech-act; the parties commit themselves under divine sanction to the treaty-terms. Abraham's readiness to swear a covenant-loyalty treaty with a pagan king reflects the covenant-patriarch's understanding that the Abrahamic covenant's blessing-to-all-nations (12:3) includes covenant-relationships with pagan neighbors, not only with Israel's descendants.</p>""",
    "25": """<p>The well dispute — Abraham "complained (<em>wayyôkaḥ</em>) about a well of water that Abimelech's servants had seized" — the first of several patriarchal well-disputes in the Negev (Isaac's well-disputes at Esek, Sitnah, and Rehoboth, 26:20-22). Water rights in the semi-arid Negev were the most critical and contentious form of property in the patriarchal economy: wells required significant labor to dig, required ongoing maintenance, and were the essential resource for both human survival and pastoral agriculture. The well-dispute context makes the subsequent treaty (vv27-31) practical as well as political: Beersheba's well is the physical basis for the covenant.</p>""",
    "26": """<p>Abimelech's denial — "I don't know who did this" — is the standard ANE response of a senior party when challenged about the actions of his subordinates: the king denies personal responsibility for what his servants did without his knowledge. Whether Abimelech's denial is credible or convenient is left ambiguous; Abraham accepts it and proceeds to the covenant-ratification. The practical resolution prioritizes the covenant-relationship (sealing the Beersheba treaty) over the well-grievance (which is satisfied by the gift of seven lambs in v30).</p>""",
    "27": """<p>"Abraham brought sheep and cattle and gave them to Abimelech, and the two men made a treaty (<em>wayyikrĕtû šĕnêhem bĕrît</em>)" — the covenant-cutting formula. The gift of sheep and cattle precedes the covenant ratification — a covenant gift establishing the treaty-context. This is the first "treaty" (<em>bĕrît</em>) between Abraham and a non-family party; the vocabulary and form are the same as the Abrahamic covenant (15:18; 17:2) and foreshadow the Israelite treaty-formula used in political agreements (Josh 9:6; 1 Sam 11:1).</p>""",
    "28": """<p>Abraham "set apart (<em>wayyaṣṣēḇ</em>) seven ewe lambs from the flock" — the deliberate separation of seven lambs from the general treaty-gift (v27) signals a special purpose for these seven. The use of seven in ANE covenant-making is well-documented: the number seven appears in treaty-oaths, covenant sacrifices, and the naming of covenant-participants (cf. seven altars in Num 23:1-4,14,29). The seven lambs function as the physical symbol of the oath — the witness-animals that embody the covenant's terms.</p>""",
    "29": """<p>Abimelech's question — "what is the meaning of these seven ewe lambs you have set apart?" — requires Abraham to articulate the symbolic function of the gift. The question-and-answer format for covenant-symbols is a consistent ANE treaty practice: the parties verbalize the meaning of the symbolic elements to ensure shared understanding of what the symbols represent. Compare the Passover instruction to articulate the meaning of the meal elements (Exod 12:26-27; 13:8) when children ask "what does this mean?"</p>""",
    "30": """<p>"Accept these seven lambs from my hand as a witness (<em>ʿēḏāh</em>) that I dug this well" — the seven lambs serve a double function: they ratify the covenant and they document the well's ownership. In a pre-written-record context, the acceptance of a symbolic gift in the presence of witnesses creates a legal record: Abimelech's acceptance of the seven lambs constitutes public acknowledgment of Abraham's prior claim to the well. The lambs as "witness" (<em>ʿēḏāh</em>) parallels the use of memorial stones as witnesses (Josh 24:27; Gen 31:48).</p>""",
    "31": """<p>Beersheba (<em>bĕʾēr šābaʿ</em>) — the place-name etymology is a double pun: "well of seven (<em>šeḇaʿ</em>)" (referring to the seven lambs) and "well of oath (<em>šĕḇûʿāh</em>)" (referring to the oath sworn there). Both meanings are embedded in the name; the narrative deliberately triggers both. Beersheba becomes one of the primary sacred sites of the patriarchal covenant-journey: Abraham (v33), Isaac (26:23-25), and Jacob (46:1) all worship YHWH at Beersheba. The later phrase "from Dan to Beersheba" (Judg 20:1; 1 Sam 3:20; 2 Sam 3:10; etc.) uses Beersheba as the southern boundary of Israel — the place Abraham named for his covenant with Abimelech.</p>""",
    "32": """<p>"Abimelech and Phicol the commander of his forces returned to the land of the Philistines" — the formal conclusion of the treaty. The mention of Phicol alongside Abimelech in the treaty-making follows the ANE protocol of having the military commander as well as the king as a treaty-party; the commander's presence ensures the treaty is binding on the military force, not just on the royal office. The "land of the Philistines" anachronism (see v1 note) frames the Gerar territory consistently for the narrative's later audience.</p>""",
    "33": """<p>"Abraham planted a tamarisk tree (<em>ʾēšel</em>) in Beersheba, and there he called on the name of the LORD, the Eternal God (<em>ʾĒl ʿÔlām</em>)" — the divine name <em>ʾĒl ʿÔlām</em> (Eternal God/God of eternity) appears only here in the OT. It identifies YHWH with the Canaanite supreme deity <em>ʾĒl</em> combined with the covenant-word <em>ʿôlām</em> (eternal/everlasting) — the same word characterizing both the Noahic (9:16) and Abrahamic (17:7) covenants. The tamarisk (<em>ʾēšel</em>) is a long-lived tree (estimated lifespan of hundreds of years) appropriate to a place named for an everlasting covenant; planting it is a permanence-gesture at the treaty-site.</p>""",
    "34": """<p>"Abraham stayed in the land of the Philistines for a long time (<em>yāmîm rabbîm</em>)" — the extended residence following the Abimelech-treaty brings the Gerar narrative to a close. The "many days" of residence contrasts with the provisional quality of the patriarchal sojourn (gēr) described throughout; Abraham lives in Gerar under the protection of the Abimelech-treaty. The residence also establishes the context for the subsequent Akedah (ch22), which begins with Abraham already in the region and proceeds to Moriah.</p>"""
  },
  "22": {
    "2": """<p>"Take your son, your only son (<em>yāḥîd</em>), whom you love — Isaac" — the triple intensification (your son / your only son / whom you love) followed by the name is the most emotionally freighted divine command in Genesis. <em>Yāḥîd</em> (only, solitary, beloved-unique) is the same word used in Jer 6:26 for mourning "an only child" and in Ps 22:20 ("my only life/soul") and Prov 4:3 ("an only son before my mother"). The slow unfolding of the command — son... only son... whom you love... Isaac — allows the full weight of what is asked to accumulate before the verb appears. "Moriah" (<em>mōriyyāh</em>) — 2 Chr 3:1 identifies this as the mountain where Solomon built the Temple in Jerusalem. The tradition connecting the Akedah site to the Temple Mount is the basis for understanding sacrifice and worship at the Temple as standing in the place where the covenant-prototype occurred.</p>""",
    "3": """<p>"Early the next morning (<em>wayyaškem ʾaḇrāhām babboqer</em>) Abraham got up" — the immediate obedience; no recorded conversation with Sarah, no delay, no recorded night of anguish (though the narrative's silence on what the night was like is one of its most powerful restraints). The early-morning departure is Abraham's covenant-action signature: he departs early for Lot-rescue (14:14 implied), for the Sodom aftermath (19:27), for the Ishmael expulsion (21:14), and now for the Akedah. "When he had cut enough wood for the burnt offering" — the practical preparation precedes the journey; Abraham does not go unprepared, hoping to find wood on the mountain.</p>""",
    "4": """<p>"On the third day Abraham looked up and saw the place in the distance" — the three-day journey in silence. The narrative gives no account of what was said or thought during those three days; the gap is the most eloquent silence in Genesis. "The third day" (<em>bayyôm haššĕlîšî</em>) carries eschatological weight throughout the OT: the day of divine resolution (Exod 19:11,16: YHWH descends on Sinai on the third day; Josh 1:11; Hos 6:2; Jonah 1:17; Esth 5:1). The resolution of the Akedah — the divine provision of the ram — occurs on the third day, establishing a pattern that NT interpreters apply to the resurrection.</p>""",
    "5": """<p>"We will worship and then we will come back to you (<em>wĕnāšûḇāh ʾălêkem</em>)" — Abraham's statement to the servants that "we" will return. Heb 11:17-19 reads this as faith: "Abraham reasoned that God could even raise the dead, and so in a manner of speaking he did receive Isaac back from death." Whether Abraham literally expected resurrection, or whether the statement conceals the true purpose from the servants, or whether the plural "we" is a slip of faith-certainty, the effect is the same: Abraham's word to the servants becomes prophetically true — both of them do return. The statement is true in a way Abraham could not have predicted when he said it.</p>""",
    "6": """<p>"Abraham took the wood for the burnt offering and placed it on his son Isaac" — the wood-bearing by Isaac. Early Christian interpretation (Tertullian, Origen) reads this as a type: Isaac carrying the wood of his own sacrifice parallels Christ carrying the cross (John 19:17). The structural parallel is precise: the only son, carrying the instrument of his own sacrifice, going willingly to the place of death, accompanied by his father. The type is explicit enough that the NT interpretation is not an imposition but a recognition of the pattern the Akedah establishes.</p>""",
    "7": """<p>Isaac's question — "where is the lamb for the burnt offering (<em>ʾayyēh haśśeh lĕʿōlāh</em>)?" — the moment of innocent unknowing. The child who is the intended sacrifice asks for the sacrifice without knowing he is it. The fire and wood are present; the lamb is absent. The question exposes the narrative's theological center: what will YHWH provide? Abraham has everything for the sacrifice except the victim — the victim is the covenant-heir, whose sacrifice would undo the covenant. The question is unanswerable by human reasoning; only divine provision can resolve it.</p>""",
    "8": """<p>"God himself will provide (<em>yirʾeh-lô ʾĕlōhîm</em>) the lamb for the burnt offering, my son" — the divine provision verb (<em>rāʾāh</em>, to see/provide — in the sense of seeing to a need) anticipates the site-name of v14 (<em>YHWH Yireh</em>, the LORD sees/provides). Whether Abraham speaks in faith (believing YHWH will intervene) or in unknowing prophecy (the words are more true than he knows), the answer is both immediately and ultimately true: God provides a ram immediately (v13) and provides "the Lamb of God" ultimately (John 1:29). "And the two of them went on together (<em>wayyēlĕkû šĕnêhem yaḥdāw</em>)" — the phrase repeated from v6; the father and son walking together toward the place of sacrifice is the most restrained and devastating image in the Akedah.</p>""",
    "9": """<p>"He bound his son Isaac (<em>wayyaʿăqōḏ ʾet-yiṣḥāq bĕnô</em>)" — the verb <em>ʿāqaḏ</em> (to bind/truss) is a hapax legomenon — it appears only here in the entire OT. The uniqueness of the word ensures the episode is remembered as "the Akedah" (the binding) in Jewish tradition. Isaac's binding makes the sacrifice formal and irreversible by human action: Abraham has done everything necessary to complete the sacrifice except the final act. The fact that Isaac (now probably a teenager or young adult, capable of physical resistance — the Midrash explores this) does not resist the binding is the narrative's implicit statement of his voluntary submission.</p>""",
    "10": """<p>"He reached out his hand and took the knife (<em>hammaʾăkelèt</em>) to slay his son" — the narrative pauses at the moment of maximum tension. Abraham's hand is extended; the knife is in his hand; the sacrifice is an instant away. The word <em>maʾăkelèt</em> (knife/cleaver, from <em>ʾākal</em>, to eat — the knife that cuts for consuming/sacrifice) appears only in the Akedah (vv6,10) and in Judg 19:29. The specific terminology for the sacrifice-knife marks this as the final technical preparation for the rite; when the angel speaks (v11), it is not before Abraham has fully committed but precisely as the commitment is completed.</p>""",
    "11": """<p>"Abraham! Abraham! (<em>ʾaḇrāhām ʾaḇrāhām</em>)" — the double-name address is the theophanic/urgent call of divine attention: "Moses! Moses!" (Exod 3:4), "Samuel! Samuel!" (1 Sam 3:10), "Simon, Simon!" (Lk 22:31), "Martha, Martha!" (Lk 10:41), "Saul, Saul!" (Acts 9:4). The doubling expresses urgency and intimacy simultaneously — the caller knows the person completely. "Here I am (<em>hinnēnî</em>)" — the third <em>hinnēnî</em> in the Akedah: Abraham responds to God's call (v1), to Isaac's call (v7), and now to the angel's call (v11) with identical availability. The consistency of his response-posture across the entire episode — "here I am" before child-call and divine-call alike — is the narrative's portrait of total covenantal presence.</p>""",
    "12": """<p>"Now I know that you fear God (<em>yĕrēʾ ʾĕlōhîm ʾattāh</em>), because you have not withheld (<em>ḥāśakta</em>) your son" — the divine assessment at the moment of proof. "Fear of God" (<em>yirʾat ʾĕlōhîm</em>) as the fundamental covenant-virtue (17:1: "walk before me and be blameless") is here confirmed by action: the test (<em>nissāh</em>, v1) produces its intended result — not information for YHWH (who knows Abraham's heart) but demonstration before the creation of the covenant-partner's character. The verb "withhold" (<em>ḥāśak</em>) will recur in v16 (human side: "you have not withheld your son") and is the exact word Paul's echo uses in Rom 8:32 (divine side: "he who did not spare his own Son — <em>ouk epheisato</em> — but gave him up for us all").</p>""",
    "13": """<p>"A ram caught by its horns in a thicket (<em>ʾayil ʾaḥar neʾĕḥaz baśśĕḇāk bĕqarnāyw</em>)" — the substitute sacrifice: a ram caught in the thicket by its head, unable to free itself. The substitute is provided not before Abraham's obedience is complete but precisely at the moment the obedience is proven: the ram appears when it is needed, not before. The ram as substitute completes the sacrifice without the covenant-heir's death — the offering is completed, the covenant-heir lives, and the pattern of substitutionary sacrifice is established as a covenant-principle. The ram "instead of his son (<em>taḥat bĕnô</em>)" is the lexical substitution formula.</p>""",
    "14": """<p>"YHWH Yireh (<em>YHWH yirʾeh</em>)" — "the LORD sees/provides"; the name plays on the same verb as Abraham's answer to Isaac in v8 (<em>yirʾeh-lô ʾĕlōhîm</em>, God will see/provide for himself). The naming of the site embeds the narrative's theological resolution in the geographic landmark: the place where YHWH provided the substitute becomes the place named for divine provision. "On the mountain of the LORD it will be provided/seen (<em>yērāʾeh</em>)" — the proverb preserved in the name points forward: what happened once at this mountain will happen again; the mountain of YHWH Yireh is the place of ongoing divine provision. 2 Chr 3:1 identifies this mountain as the Temple Mount — the place of ongoing sacrifice became the place where the sacrificial system was centered.</p>""",
    "15": """<p>The angel of the LORD calling "a second time (<em>šēnît</em>)" from heaven signals a second divine address — distinct from the rescue-call of vv11-12. The second call issues a formal divine oath, the most solemn possible form of commitment. The two angelic calls structure the Akedah's climax in two movements: first, the rescue (vv11-12, "don't harm him; now I know you fear God"); second, the oath (vv16-18, the binding of YHWH to his own commitment by self-oath). The rescue is the immediate mercy; the oath is the covenantal consequence of Abraham's faithfulness.</p>""",
    "16": """<p>"I swear by myself (<em>bî nišbàʿtî</em>) declares the LORD, that because you have done this and have not withheld your son, your only son" — the divine self-oath, the most absolute possible form of commitment. YHWH swears by himself because there is no greater authority by which to swear. Heb 6:13-18 cites this: "since there was no one greater for him to swear by, he swore by himself... so that, by two unchangeable things in which it is impossible for God to lie, we who have fled to take hold of the hope set before us may be greatly encouraged." The oath transforms the Abrahamic covenant from promise to oath-bound commitment — ratified by YHWH's self-swearing at the moment of Abraham's maximum faithfulness.</p>""",
    "17": """<p>"I will surely bless you (<em>bārēk ʾăḇārekkā</em>) and make your descendants as numerous as the stars in the sky and as the sand on the seashore" — the stars and sand restatements of the offspring-promise (13:16; 15:5) are combined for the first time, adding the military element: "your descendants will take possession of the cities of their enemies." The military dimension of the Abrahamic blessing — taking "the gates of your enemies" — is new at this point; it will be developed in the conquest narratives (Josh 6:1-27). The oath-ratification at the Akedah's conclusion is the fullest statement of the Abrahamic covenant in Genesis.</p>""",
    "18": """<p>"Through your offspring all nations on earth will be blessed (<em>wĕhitbārĕḵû bĕzarʿăkā kōl gôyê hāʾāreṣ</em>) because you have obeyed me (<em>ʾēqeb ʾăšer šāmaʿtā bĕqōlî</em>)" — the universal blessing formula (12:3; 18:18) with an explicit grounding: "because you have obeyed me." The obedience of the Akedah becomes the narrative basis for the covenant-oath. Paul cites this verse (Gal 3:8,16) arguing that "your offspring" (<em>zāraʿ</em>, singular) ultimately refers to Christ, through whom "all nations are blessed." The singular seed, the obedient son who did not escape sacrifice (in the type), is the ultimate fulfillment of the Akedah's theological logic.</p>""",
    "19": """<p>"Then Abraham returned to his servants, and they set off together for Beersheba" — Isaac is not mentioned by name in the return from Moriah. The narrative says "Abraham returned" to his servants; only Abraham is named. Where Isaac was between the Akedah and Rebekah's arrival (24:62-67) is one of the OT's most examined silences. The narrative gap has generated extensive rabbinic and patristic reflection: some traditions (Pirke de-Rabbi Eliezer; the Zohar) suggest Isaac went to study in the "garden of Eden" or elsewhere. The narrative's silence protects the Akedah's mystery — Isaac's post-Akedah life begins with Rebekah, not with a narrative transition.</p>""",
    "20": """<p>"Milcah is also a mother; she has borne sons to your brother Nahor" — the Nahor genealogy is positioned here (after the Akedah and before Isaac's marriage quest in ch24) as preparatory narrative: Rebekah (Bethuel's daughter, v23) is introduced before she becomes central in ch24. The genealogical list establishes that the covenant-household's marriage-pool includes Nahor's descendants — the principle that Isaac should not marry a Canaanite woman (24:3) and should marry from within the extended family (24:4) requires the reader to know where the extended family is and who it contains.</p>""",
    "21": """<p>The sons of Nahor's wife Milcah — Uz the firstborn (the land of Uz appears in Job 1:1), Buz (associated with an Arabian tribe in Jer 25:23), Kemuel the father of Aram (connected to the Aramean peoples) — establish the geographic range of Nahor's line. The descendants spread across the Syro-Mesopotamian region, consistent with Nahor's residence at "Nahor" (the city, 24:10) in the Paddan-Aram region (northwest Mesopotamia). The genealogy maps the social landscape of the extended Abrahamic family in the region from which Isaac's wife will come.</p>""",
    "22": """<p>Kesed, Hazo, Pildash, Jidlaph, and Bethuel — the six remaining sons of Nahor and Milcah. Kesed is possibly the eponym of the Chaldeans (<em>Kaśdîm</em>); Hazo may be connected to an Arabian tribal name; the others are not attested outside this list. The function of the genealogy is etiological (explaining the origin of various Syrian/Aramean peoples) and narrative (establishing Bethuel as Nahor's eighth son, the father of Rebekah).</p>""",
    "23": """<p>"Bethuel became the father of Rebekah (<em>ʾet-Riḇqāh</em>)" — the key genealogical note. Rebekah's name appears for the first time; the genealogy builds to this single name before continuing to Nahor's concubine's sons. The positioning of Rebekah's introduction immediately after the Akedah and before ch24's marriage quest is the narrative's structural preparation: the covenant-heir has survived the ultimate test; his covenant-wife is now introduced by lineage before she is introduced by character (ch24). The narrative knows where the story is going before the characters do.</p>""",
    "24": """<p>Nahor's concubine Reumah and her sons (Tebah, Gaham, Tahash, Maakah) — a secondary genealogical branch. Maakah is the name of an Aramean kingdom north of the Sea of Galilee (Deut 3:14; Josh 12:5; 13:11,13; 2 Sam 10:6-8), suggesting the eponymous ancestor is this Maakah. The concubine-sons expand the reach of Nahor's line into the northern Aramean territories. The dual genealogy (wife's sons + concubine's sons) parallels Abraham's dual line (Sarah's Isaac + Hagar's Ishmael; later Keturah's sons) — the patriarchal household's multiple-line family structure is a consistent ANE pattern.</p>"""
  },
  "23": {
    "1": """<p>"Sarah lived to be a hundred and twenty-seven years old (<em>meʾāh šānāh wĕʿeśrîm šānāh wĕšeḇaʿ šānîm</em>)" — Sarah is the only woman in the OT whose age at death is given. The recording of her years with the same detailed formula used for the patriarchs' ages (the years are listed in three groupings — a distinctive pattern) dignifies her as a covenant-figure of equal status. She is 90 at Isaac's birth (17:17); Isaac is therefore 37 when Sarah dies. The age-recording places Sarah within the covenant-genealogy framework that defines the patriarchal period as a specific historical span.</p>""",
    "2": """<p>"She died at Kiriath Arba (that is, Hebron) in the land of Canaan" — Kiriath Arba (<em>qiryat ʾarbaʿ</em>, "city of four") is the pre-Israelite name for Hebron; Josh 14:15 identifies Arba as "the greatest man among the Anakites." Hebron (from <em>ḥāḇar</em>, to join/be a companion) becomes the patriarchal home-base and burial site. "Abraham went to mourn (<em>lispōd</em>) for Sarah and to weep (<em>liḇkôt</em>) over her" — the two verbs distinguish the formal mourning rite (<em>sāpad</em>, to wail/beat oneself — the formal mourning ceremony) from the personal grief (<em>bākāh</em>, to weep). Abraham performs both the social obligation and the personal grief.</p>""",
    "3": """<p>"Abraham rose from beside his dead wife and spoke to the Hittites" — the physical detail of "rising from beside his dead wife (<em>mēʿal pĕnê mētô</em>)" depicts the initial mourning position: sitting with the body, then rising to attend to burial practicalities. The transition from grief to action is the ANE burial protocol: the period of initial mourning (sitting beside the dead) was followed by the practical necessity of rapid burial (in the heat of the ANE, burial within 24 hours was medically necessary). The Hittites of Hebron are the local population with whom Abraham must negotiate for burial ground.</p>""",
    "4": """<p>"I am a foreigner and stranger (<em>gēr-wĕtôšāḇ</em>) among you" — Abraham's formal self-identification in the legal negotiation. The double term <em>gēr-wĕtôšāḇ</em> appears together only here, in Lev 25:47, and in Ps 39:12. The <em>gēr</em> is a resident alien without land rights; the <em>tôšāḇ</em> is a temporary settler. Together they describe Abraham's permanent outsider status: he has lived in Canaan for decades but owns no land. The purchase of the Machpelah cave is the first moment of legal land-ownership in the promised land — the covenant-patriarch buys a grave before he can inhabit the inheritance.</p>""",
    "5": """<p>The Hittites' response — "listen to us" (<em>šĕmaʿēnû</em>) — initiates the formal ANE negotiation protocol. The instruction to "listen to us" before the offer establishes the public, deliberative character of the gate-council transaction. The Hittite community's willingness to negotiate with Abraham reflects his regional status — he is a stranger but a "mighty prince (<em>nĕśîʾ ʾĕlōhîm</em>, prince of God/a great prince)" in their estimation. The Gerar episode (20:15: "my land is before you"), the treaty with Abimelech (21:22-23), and Abraham's military reputation (ch14) have established him as a significant regional figure despite his <em>gēr</em> status.</p>""",
    "6": """<p>"You are a mighty prince (<em>nĕśîʾ ʾĕlōhîm</em>) among us. Bury your dead in the choicest of our tombs" — the Hittite council's generous offer would solve Abraham's immediate problem (Sarah's burial) but without creating legal title. In the ANE, permission to use someone else's tomb was a social concession, not a property transfer; the heirs of the tomb's owner could later reclaim it. Abraham's insistence on purchasing rather than borrowing a tomb (vv8-9,13) reflects his understanding that a covenant-heir must have legal title to a portion of the promised land, not merely social permission to use it temporarily.</p>""",
    "7": """<p>"Abraham rose and bowed down (<em>wayyiqqad ʾaḇrāhām lipnê ʿam-hāʾāreṣ</em>) before the people of the land" — the prostration before the Hittite council is the standard protocol of respect before the local authority whose approval is needed. "The people of the land (<em>ʿam-hāʾāreṣ</em>)" — a technical term for the established landowning citizens of the territory; the council that has authority to ratify property transfers. Abraham's bow is a social-legal gesture, not worship — the same gesture used when approaching a superior for a legal transaction (cf. Ruth 2:10; 2 Sam 14:4).</p>""",
    "8": """<p>"If you are willing to let me bury my dead (<em>ʾim yēš ʾet-napšĕkem liqbōr ʾet-mētî</em>)" — literally "if it is in your soul/desire to bury my dead." The conditional framing of the request is the standard ANE negotiation protocol: the petitioner phrases the request as a matter of the grantor's willingness, not as a demand. "Intercede with Ephron (<em>pĕgĕʿû-bî bĕʿeprôn</em>)" — Abraham requests the council to mediate with the specific landowner rather than negotiating directly; using the community council as intermediary was the formal land-purchase protocol in the ANE city-gate system.</p>""",
    "9": """<p>"So he will sell me the cave of Machpelah (<em>mĕʿārat hammaḵpēlāh</em>)" — Machpelah may derive from <em>kāpal</em> (to double) — "double cave" — perhaps referring to a two-chambered natural cave formation. "At the end of his field" — a specific location within the larger Ephron property; Abraham is not asking for the whole field but for the specific cave and its immediate surroundings. "For the full price (<em>bĕkesep māleʾ</em>, at full silver/money)" — Abraham explicitly requests to pay full market value, not a discounted charitable price; the full-price insistence is the legal key to creating unambiguous title.</p>""",
    "10": """<p>"Ephron the Hittite was sitting among his people (<em>yōšēḇ bĕtôk bĕnê-ḥēt</em>)" — the description of Ephron's position within the Hittite community establishes his civic standing; he is a full member of the community with legal authority to conduct property transactions. "He replied to Abraham in the hearing of all the Hittites who had come to the gate of his city (<em>kōl bāʾê šaʿar ʿîrô</em>)" — the city gate as the ANE legal forum: land transactions required public witnesses at the city gate (Ruth 4:1-11; Deut 25:7-9). The multiple witnesses make the transaction legally binding and publicly documented.</p>""",
    "11": """<p>"I give you the field, and I give you the cave that is in it" — Ephron's public "gift" is the standard ANE negotiation opening: appearing to give everything for free while actually naming a price in the next breath (v15). The triple "I give" (<em>nĕtattiha... nĕtattîha... nĕtattiha</em>) sounds generous but functions as a negotiating position. "In the presence of my people (<em>lĕʿênê bĕnê-ʿammî</em>) I give it to you" — the public nature of the offer is part of its legal function; the witnesses ensure that what was said is on record. Abraham's response (v13) correctly reads this as a price-setting gesture, not an actual gift.</p>""",
    "12": """<p>"Again Abraham bowed down (<em>wayyištaḥû ʾaḇrāhām lipnê ʿam-hāʾāreṣ</em>) before the people of the land" — the repeated bow acknowledges Ephron's public generosity while positioning Abraham to make the counter-proposal of actual payment. The reiterated bow maintains the social-honor framework of the negotiation: Abraham is not challenging Ephron's generosity but is insisting that the relationship be structured on legal purchase rather than social obligation. The bow between transactions marks each stage of the formal process.</p>""",
    "13": """<p>"I will pay the price of the field (<em>nĕtatî kesef haśśādeh</em>)" — Abraham's insistence on paying transforms the social-obligation frame (Ephron's "gift") into a legal-title frame (Abraham's "purchase"). In ANE property law, a gift could be recalled by the donor's heirs; a sale created permanent legal title in the buyer. Abraham's insistence on "paying the price" is not mere scrupulousness but a strategic legal decision: he needs unambiguous, irrecusable title to the first piece of land in the promised inheritance, not a revocable social concession.</p>""",
    "14": """<p>Ephron's response — "listen to me (<em>šĕmaʿēnî</em>)" — mirrors Abraham's opening formula (v8) and the Hittites' opening (v6): the "listen to me" framing is the formal speech-marker for a statement with legal weight in the ANE negotiation context. The response to Abraham's insistence on payment is a return to the negotiation, now on Abraham's terms: Ephron will name a price. The interplay of "give" language and "buy" language across the negotiation maps the transition from social courtesy to legal transaction.</p>""",
    "15": """<p>"The land is worth four hundred shekels of silver (<em>ʾarbaʿ-meʾôt šeqel-kesep</em>) — but what is that between you and me?" — the dismissive "what is that between you and me?" is the ANE negotiator's technique of naming a large price while minimizing its apparent significance. 400 shekels of silver is a substantial sum; for comparison, David's purchase of the Araunah threshing floor (the future Temple site) cost 50 shekels (2 Sam 24:24) or 600 shekels of gold (1 Chr 21:25 — different metals, different transaction). The patriarchal silver standard and the later Davidic transaction involve different commodities and different periods; the Machpelah price is consistent with known Nuzi tablet land-purchase values for comparable property.</p>""",
    "16": """<p>"Abraham agreed to Ephron's terms and weighed out for him the price he had named... four hundred shekels of silver, according to the weight current among the merchants (<em>ʿōḇēr laṣṣōḥēr</em>)" — the legal precision of the payment description establishes the transaction's formal validity. Silver was weighed rather than coined in pre-monetary ANE commerce (coinage was not invented until ca. 7th century BCE in Lydia); the weighing "according to the weight current among the merchants" specifies the standard used — a recognized commercial weight standard rather than a private measure. The public weighing at the city gate, according to the standard measure, in the hearing of all witnesses, is the ANE equivalent of a notarized transaction.</p>""",
    "17": """<p>"Ephron's field in Machpelah near Mamre — both the field and the cave in it, and all the trees within the borders of the field — was deeded (<em>wayyāqom</em>)" — the deed description's specificity mirrors ANE property-transfer documents. The Nuzi tablets and Egyptian deeds consistently itemize: the field, the structures on the field, and the trees within the field boundaries (trees were separately valuable as long-lived agricultural assets). The completeness of the inventory — field + cave + all trees within borders — is the legal documentation of everything transferred. "Was deeded (<em>wayyāqom</em>, was established/ratified)" — the legal standing (<em>qûm</em>) of the transaction is its irrevocability.</p>""",
    "18": """<p>"To Abraham as his property (<em>lĕʾaḇrāhām lĕmiqnāh</em>), in the presence of all the Hittites who had come to the gate of the city" — the deed is formally concluded. <em>Miqnāh</em> (purchased property/acquisition) from <em>qānāh</em> (to buy/acquire) is the technical legal term for purchased as opposed to inherited or gifted property. The witnesses — "all the Hittites who had come to the gate" — constitute the public record. In a pre-writing or pre-formal-deed culture, mass witnessing at the city gate was the mechanism of legal record: the community's memory was the title document. The entire Hittite community who witnessed the transaction can testify to Abraham's legal title.</p>""",
    "19": """<p>"Afterward Abraham buried his wife Sarah in the cave in the field of Machpelah near Mamre (which is at Hebron) in the land of Canaan" — the burial closes the transaction. The purpose of the legal process is fulfilled: Sarah is buried with legal title in the land promised to Abraham's descendants. Machpelah becomes the patriarchal tomb: Abraham himself (25:9-10), Isaac and Rebekah (49:31), Jacob and Leah (49:31; 50:13) will all be buried here. The cave of Machpelah near Mamre/Hebron is one of the few sites whose patriarchal association is maintained in continuous tradition; the Cave of the Patriarchs in modern Hebron (the Ibrahimi Mosque) is identified with this site.</p>""",
    "20": """<p>"The field and the cave in it were deeded (<em>wayyāqom</em>) to Abraham by the Hittites as a burial site" — the closing legal summary reiterates the transaction's legal validity. The redundancy is deliberate: this is the only land Abraham legally owns in the promised land during his lifetime, and its legal standing must be unambiguous. The purchase of a burial cave as the first tangible possession of the promised land is one of the OT's most poignant ironies: the covenant-heir owns a grave in the land his descendants will inherit. Stephen cites this in his Acts 7 speech (Acts 7:16 — with some differences): the patriarchs owned no land in the promise except a burial site.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [20, 21, 22, 23]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis context total: {total_chs} chapters, {total_vv} verses')
    print('Genesis 20–23 mkt-context written.')

if __name__ == '__main__':
    main()
